    def _extract_assertions(self, root: ET.Element) -> List[Dict]:
        """Extract assertions from SAML response"""
        assertions = []
        
        # Find all assertions
        assertion_elements = root.findall("{urn:oasis:names:tc:SAML:2.0:assertion}Assertion")
        
        for assertion in assertion_elements:
            assertion_data = {
                "id": assertion.get("ID"),
                "issue_instant": assertion.get("IssueInstant"),
                "version": assertion.get("Version"),
                "issuer": None,
                "subject": None,
                "conditions": None,
                "authn_statement": None,
                "attribute_statements": []
            }
            
            # Extract issuer
            issuer_element = assertion.find("{urn:oasis:names:tc:SAML:2.0:assertion}Issuer")
            if issuer_element is not None:
                assertion_data["issuer"] = issuer_element.text
            
            # Extract subject
            subject_element = assertion.find("{urn:oasis:names:tc:SAML:2.0:assertion}Subject")
            if subject_element is not None:
                name_id = subject_element.find("{urn:oasis:names:tc:SAML:2.0:assertion}NameID")
                if name_id is not None:
                    assertion_data["subject"] = {
                        "name_id": name_id.text,
                        "format": name_id.get("Format")
                    }
            
            # Extract conditions
            conditions_element = assertion.find("{urn:oasis:names:tc:SAML:2.0:assertion}Conditions")
            if conditions_element is not None:
                assertion_data["conditions"] = {
                    "not_before": conditions_element.get("NotBefore"),
                    "not_on_or_after": conditions_element.get("NotOnOrAfter")
                }
            
            # Extract authentication statement
            authn_statement = assertion.find("{urn:oasis:names:tc:SAML:2.0:assertion}AuthnStatement")
            if authn_statement is not None:
                assertion_data["authn_statement"] = {
                    "authn_instant": authn_statement.get("AuthnInstant"),
                    "session_index": authn_statement.get("SessionIndex"),
                    "authn_context": {
                        "authn_context_class_ref": None
                    }
                }
                
                # Extract authn context
                authn_context = authn_statement.find("{urn:oasis:names:tc:SAML:2.0:assertion}AuthnContext")
                if authn_context is not None:
                    context_class_ref = authn_context.find("{urn:oasis:names:tc:SAML:2.0:assertion}AuthnContextClassRef")
                    if context_class_ref is not None:
                        assertion_data["authn_statement"]["authn_context"]["authn_context_class_ref"] = context_class_ref.text
            
            # Extract attribute statements
            attribute_statements = assertion.findall("{urn:oasis:names:tc:SAML:2.0:assertion}AttributeStatement")
            for attr_stmt in attribute_statements:
                attributes = []
                attr_elements = attr_stmt.findall("{urn:oasis:names:tc:SAML:2.0:assertion}Attribute")
                for attr in attr_elements:
                    attr_data = {
                        "name": attr.get("Name"),
                        "friendly_name": attr.get("FriendlyName"),
                        "values": []
                    }
                    attr_values = attr.findall("{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue")
                    for val in attr_values:
                        attr_data["values"].append(val.text)
                    attributes.append(attr_data)
                assertion_data["attribute_statements"].append({
                    "attributes": attributes
                })
            
            assertions.append(assertion_data)
        
        return assertions
    
    def _validate_assertions(self, assertions: List[Dict]):
        """Validate assertions"""
        if not assertions:
            raise SAMLSecurityError("No assertions found in SAML response")
        
        for assertion in assertions:
            # Validate required fields
            if not assertion.get("id"):
                raise SAMLSecurityError("Assertion missing ID")
            
            # Validate timestamp
            issue_instant = assertion.get("issue_instant")
            if issue_instant:
                try:
                    # Basic timestamp validation
                    datetime.fromisoformat(issue_instant.replace('Z', '+00:00'))
                except ValueError:
                    raise SAMLSecurityError("Invalid timestamp in assertion")
            
            # Validate subject
            subject = assertion.get("subject")
            if not subject or not subject.get("name_id"):
                raise SAMLSecurityError("Assertion missing subject or name ID")
            
            # Validate conditions
            conditions = assertion.get("conditions")
            if conditions:
                not_on_or_after = conditions.get("not_on_or_after")
                if not_on_or_after:
                    try:
                        exp_time = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00'))
                        if exp_time < datetime.utcnow():
                            raise SAMLSecurityError("Assertion has expired")
                    except ValueError:
                        raise SAMLSecurityError("Invalid expiration timestamp in assertion")

